const raw = $json.output || '';
const remoteJid = $('Inicio (Router)').item.json.body.data.key.remoteJid;
const instanceName = $('Inicio (Router)').item.json.evolutionInstance;

let t = raw;
// Markdown → WhatsApp
t = t.replace(/\*\*(.+?)\*\*/gs, '*$1*');
t = t.replace(/__(.+?)__/g, '*$1*');
t = t.replace(/^#{1,3} +(.+)/gm, '*$1*');
t = t.replace(/^[ \t]*[-•·] (.+)/gm, '💡 $1'); // -, •, · → 💡
t = t.replace(/~~(.+?)~~/g, '~$1~');
t = t.replace(/```[\s\S]*?```/g, '').replace(/`([^`]+)`/g, '$1');
t = t.trim();

// Dividir por doble salto de línea (párrafos)
let bloques = t.split(/\n{2,}/).map(b => b.trim()).filter(b => b.length > 0);

// Fallback: si hay un bloque largo sin párrafos, dividir por oraciones
if (bloques.length === 1 && bloques[0].length > 280) {
  const texto = bloques[0];
  const oraciones = texto.split(/(?<=[.!?;])\s+(?=[A-ZÁÉÍÓÚÑ💡✅📌📅⏰📧💡\-\d])/);
  const reagrupado = [];
  let actual = '';
  for (const o of oraciones) {
    const candidato = actual ? actual + ' ' + o : o;
    if (actual && candidato.length > 260) {
      reagrupado.push(actual.trim());
      actual = o;
    } else {
      actual = candidato;
    }
  }
  if (actual.trim()) reagrupado.push(actual.trim());
  bloques = reagrupado.length > 1 ? reagrupado : [texto];
}

// Sub-dividir bloques aún muy largos (> 700 chars) por línea
const chunks = [];
for (const bloque of bloques) {
  if (bloque.length <= 700) {
    chunks.push(bloque);
  } else {
    const lineas = bloque.split('\n');
    let actual = '';
    for (const linea of lineas) {
      if (actual && (actual + '\n' + linea).length > 700) {
        chunks.push(actual.trim());
        actual = linea;
      } else {
        actual = actual ? actual + '\n' + linea : linea;
      }
    }
    if (actual.trim()) chunks.push(actual.trim());
  }
}

const final = chunks.length > 0 ? chunks : [t || ''];
return final.map(msg => ({ json: { mensaje: msg, remoteJid, instanceName } }));

